// app/lawyers/page.tsx
import { getAllLawyers } from "../services/lawyersService";
import { LawyerResponse } from "../models/lawyersModel";
import SearchFilters from "./SearchFilters";
import LawyerList from "./LawyerList";

interface Props {
  searchParams: {
    search?: string;
    specialty?: string;
    location?: string;
  };
}

export default async function Lawyers({ searchParams }: Props) {
  const lawyersResponse: LawyerResponse = await getAllLawyers();

  if (lawyersResponse?.error) {
    throw new Error(lawyersResponse?.message);
  }

  const lawyers = lawyersResponse.data.data;

  // 🔥 SERVER-SIDE FILTERING
  const filteredLawyers = lawyers.filter((lawyer) => {
    const matchesSearch =
      !searchParams.search ||
      lawyer.name.toLowerCase().includes(searchParams.search.toLowerCase());

    const matchesSpecialty =
      !searchParams.specialty ||
      searchParams.specialty === "All" ||
      lawyer.specialty === searchParams.specialty;

    const matchesLocation =
      !searchParams.location ||
      searchParams.location === "All" ||
      lawyer.location === searchParams.location;

    return matchesSearch && matchesSpecialty && matchesLocation;
  });

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-900 to-blue-700 text-white py-16">
        <h1 className="text-4xl font-bold text-center">Find Expert Lawyers</h1>
      </div>

      {/* Client Filters */}
      <SearchFilters />

      {/* Lawyer List */}
      <LawyerList lawyers={filteredLawyers} />
    </div>
  );
}
